                    </div>
                    <Users className="w-5 h-5 text-muted-foreground" />
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Services Chart */}
            <Card>
              <CardContent className="p-4 md:p-6">
                <div className="mb-4">
                  <h3 className="text-section-title text-foreground">
                    Serviços Mais Agendados
                  </h3>
                  <p className="text-body text-muted-foreground">
                    Distribuição dos agendamentos por tipo de serviço no período selecionado
                  </p>
                </div>

                {dashboardData.topServices.length > 0 ? (
                  <>
                    <ChartContainer
                      config={chartConfig}
                      className="mx-auto aspect-square max-h-[350px] w-full max-w-[350px]"
                    >
                      <PieChart>
                        <ChartTooltip
                          cursor={false}
                          content={<ChartTooltipContent hideLabel />}
                        />
                        <Pie
                          data={dashboardData.topServices}
                          dataKey="value"
                          nameKey="name"
                          cx="50%"
                          cy="50%"
                          outerRadius="80%"
                          innerRadius="50%"
                          strokeWidth={2}
                        >
                          {dashboardData.topServices.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.color} />
                          ))}
                        </Pie>
                      </PieChart>
                    </ChartContainer>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2 mt-6">
                      {dashboardData.topServices.map((item, index) => (
                        <div key={index} className="flex items-center gap-2">
                          <div
                            className="w-3 h-3 rounded-full"
                            style={{ backgroundColor: item.color }}
                          />
                          <span className="text-body text-muted-foreground truncate">
                            {item.name}: {item.value} agendamentos
                          </span>
                        </div>
                      ))}
                    </div>
                  </>
                ) : (
                  <div className="h-[250px] flex items-center justify-center">
                    <p className="text-muted-foreground">
                      Nenhum agendamento encontrado para o período selecionado
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>
          </>
        )}
      </div>
    </EasySalonLayout>
  );
}
